import math

def agglomerative_clustering(X: list, n_clusters: int, linkage: str = 'single') -> list:
    """
    Perform agglomerative hierarchical clustering.

    Args:
        X: Data points, shape (n_samples, n_features)
        n_clusters: Number of clusters to form
        linkage: 'single', 'complete', or 'average'

    Returns:
        List of cluster labels for each sample
    """
    n = len(X)

    # Precompute all pairwise Euclidean distances between individual points
    def euclidean(i, j):
        return math.sqrt(sum((X[i][k] - X[j][k]) ** 2 for k in range(len(X[i]))))

    point_dist = [[0.0] * n for _ in range(n)]
    for i in range(n):
        for j in range(i + 1, n):
            d = euclidean(i, j)
            point_dist[i][j] = d
            point_dist[j][i] = d

    # Initialize: each point is its own cluster
    # clusters maps cluster_id -> list of point indices
    clusters = {i: [i] for i in range(n)}

    def inter_cluster_distance(ci, cj):
        """Compute distance between two clusters based on linkage method."""
        pts1 = clusters[ci]
        pts2 = clusters[cj]
        distances = [point_dist[p1][p2] for p1 in pts1 for p2 in pts2]
        if linkage == 'single':
            return min(distances)
        elif linkage == 'complete':
            return max(distances)
        elif linkage == 'average':
            return sum(distances) / len(distances)
        else:
            raise ValueError(f"Unknown linkage: {linkage}")

    # Iteratively merge closest cluster pairs
    while len(clusters) > n_clusters:
        cluster_ids = sorted(clusters.keys())
        best_dist = float('inf')
        best_pair = None

        for i in range(len(cluster_ids)):
            for j in range(i + 1, len(cluster_ids)):
                ci, cj = cluster_ids[i], cluster_ids[j]  # ci < cj always
                d = inter_cluster_distance(ci, cj)
                # Tie-break: prefer smallest first index, then smallest second index
                if best_pair is None or d < best_dist or (d == best_dist and (ci, cj) < best_pair):
                    best_dist = d
                    best_pair = (ci, cj)

        # Merge larger-index cluster into smaller-index cluster
        ci, cj = best_pair  # ci < cj guaranteed by sorted iteration
        clusters[ci].extend(clusters[cj])
        del clusters[cj]

    # Assign labels: sorted cluster index order -> label 0, 1, 2, ...
    labels = [0] * n
    for label, cluster_id in enumerate(sorted(clusters.keys())):
        for point_idx in clusters[cluster_id]:
            labels[point_idx] = label

    return labels

