import numpy as np

def agglomerative_clustering(X: list, n_clusters: int, linkage: str = 'single') -> list:
    """
    Perform agglomerative hierarchical clustering using NumPy.

    Args:
        X: Data points, shape (n_samples, n_features)
        n_clusters: Number of clusters to form
        linkage: 'single', 'complete', or 'average'

    Returns:
        List of cluster labels for each sample
    """
    X_np = np.array(X, dtype=float)
    n = X_np.shape[0]

    # Vectorized pairwise Euclidean distance matrix: shape (n, n)
    # Broadcasting: diff[i, j] = X[i] - X[j]
    diff = X_np[:, np.newaxis, :] - X_np[np.newaxis, :, :]  # (n, n, features)
    point_dist = np.sqrt((diff ** 2).sum(axis=-1))           # (n, n)

    # Initialize clusters: cluster_id -> array of point indices
    clusters = {i: [i] for i in range(n)}

    def inter_cluster_distance(ci, cj):
        """Vectorized inter-cluster distance using precomputed point distances."""
        pts1 = clusters[ci]
        pts2 = clusters[cj]
        # np.ix_ builds an open mesh for fancy indexing: sub_dist[a,b] = dist(pts1[a], pts2[b])
        sub_dist = point_dist[np.ix_(pts1, pts2)]
        if linkage == 'single':
            return sub_dist.min()
        elif linkage == 'complete':
            return sub_dist.max()
        elif linkage == 'average':
            return sub_dist.mean()
        else:
            raise ValueError(f"Unknown linkage: {linkage}")

    # Build initial distance matrix between clusters (upper triangle)
    # For efficiency, maintain a dict of cluster-pair -> distance
    cluster_ids = list(range(n))
    dist_cache = {}
    for i in range(n):
        for j in range(i + 1, n):
            dist_cache[(i, j)] = point_dist[i, j]  # singletons: direct point distance

    while len(clusters) > n_clusters:
        # Find the closest cluster pair with tie-breaking
        best_dist = np.inf
        best_pair = None
        active_ids = sorted(clusters.keys())

        for idx_i, ci in enumerate(active_ids):
            for cj in active_ids[idx_i + 1:]:
                key = (ci, cj)  # ci < cj guaranteed
                if key not in dist_cache:
                    dist_cache[key] = inter_cluster_distance(ci, cj)
                d = dist_cache[key]
                if best_pair is None or d < best_dist or (d == best_dist and key < best_pair):
                    best_dist = d
                    best_pair = key

        ci, cj = best_pair  # ci < cj; merge cj into ci
        clusters[ci].extend(clusters[cj])
        del clusters[cj]

        # Invalidate cached distances involving the merged cluster (cj is gone)
        # Recompute distances from ci (now enlarged) to all remaining clusters
        keys_to_remove = [k for k in dist_cache if cj in k]
        for k in keys_to_remove:
            del dist_cache[k]

        # Precompute updated distances from ci to all other active clusters
        active_ids = sorted(clusters.keys())
        for other in active_ids:
            if other == ci:
                continue
            key = (min(ci, other), max(ci, other))
            dist_cache[key] = inter_cluster_distance(min(ci, other), max(ci, other))

    # Assign labels by sorted cluster index order
    labels = np.zeros(n, dtype=int)
    for label, cluster_id in enumerate(sorted(clusters.keys())):
        labels[clusters[cluster_id]] = label

    return labels.tolist()
